import{_ as i,c as l,a3 as t,o}from"./chunks/framework.BDUoXecB.js";const S=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"documents/forOpenAPISpecification/prerequisite.md","filePath":"documents/forOpenAPISpecification/prerequisite.md"}'),a={name:"documents/forOpenAPISpecification/prerequisite.md"};function n(r,e,u,p,s,c){return o(),l("div",null,e[0]||(e[0]=[t('<h2 id="前提条件" tabindex="-1">前提条件 <a class="header-anchor" href="#前提条件" aria-label="Permalink to &quot;前提条件&quot;">​</a></h2><p>本規約は以下の前提で作成されたものである。</p><ul><li>業務システム向けの Web API 提供 <ul><li>サードパーティ向けに広く開発する Web API ではなく、限られたクライアントやシステムと連携すること</li><li>いわゆる、LSUDs（Large Set of Unknown Developers）ではなく、SSKDs（Small Set of Known Developers）を対象とする</li></ul></li></ul><ul><li>RESTish な Web API <ul><li>原理的な REST を必ずしも守る必要はないが、例えば HTTP メソッドは、参照は GET、登録は POST、更新は PUT や PATCH、削除は DELETE で使い分けていたり、Web API の要求が成功すれば 200（OK）、204（No Content）を返し、リソースが無ければ 404（Not Found）、操作に失敗すれば 500 系のエラーを返すといったことを指す</li><li>本規約を利用するに当たり必須条件ではないが、定義例などはそれに基づいて記載しているので注意する</li></ul></li></ul><ul><li>スキーマファースト <ul><li>OpenAPI Specification の定義ファイルを駆動に、クライアント・サーバサイドのコード生成やモック時の利用に用い、高速な Web API 開発につなげることを前提とする <ul><li>Python における、FastAPI・Django REST Framework のように、アプリケーションコードから OpenAPI document を自動生成する開発手法も存在するが、本規約はこれは想定しない</li></ul></li><li>定義ファイルの完成度はできるかぎり高め、コード生成やドキュメントの価値を高める <ul><li>OAS 定義からコードを生成し、通常は記載した型・項目長・最大～最小・enum・必須定義・正規表現フォーマットでバリデーションを行い、カバーできない部分のバリデーションをアプリケーション固有ロジックとして実装する方針とする。例えば、複数項目間のチェックや DB を確認しないと行えないチェックである</li><li>ドキュメントとしての価値を高めるため、その API 呼び出しで発生しうる全ての HTTP ステータスコードを記載する <ul><li>API の振る舞いを読み手に伝えるものとして、どのような異常系があるかは有用な場合が多いからである</li></ul></li></ul></li></ul></li><li>JavaScript/TypeScript、Java、Go のエコシステムがターゲット <ul><li>OpenAPI Specification は広く受け入れられており、コレに対応する様々なツールやフレームワークといったエコシステムがあり、中には定義された設定がうまく認識されない場合がある。本規約では対応していないツールが多い場合、特定の記法を非推奨とすることがあり、同時にその理由も説明する</li><li>全ての言語・フレームワーク・ツールの対応状況は調査しきれていないため、利用するプロダクトの対応状況は利用者側で確認をお願いする</li></ul></li></ul>',5)]))}const d=i(a,[["render",n]]);export{S as __pageData,d as default};
